fun optimalBst(arr: IntArray): Int {
    val n = arr[0]
    val freq = IntArray(n) { arr[it + 1] }

    val cost = Array(n) { IntArray(n) }
    for (i in 0 until n) cost[i][i] = freq[i]

    for (len in 2..n) {
        for (i in 0..n - len) {
            val j = i + len - 1
            cost[i][j] = Int.MAX_VALUE
            val freqSum = (i..j).sumOf { freq[it] }

            for (r in i..j) {
                val left = if (r > i) cost[i][r - 1] else 0
                val right = if (r < j) cost[r + 1][j] else 0
                val c = left + right + freqSum
                if (c < cost[i][j]) cost[i][j] = c
            }
        }
    }

    return cost[0][n - 1]
}

pub fn optimal_bst(arr: &[i32]) -> i32 {
    let n = arr[0] as usize;
    let freq: Vec<i32> = arr[1..=n].to_vec();

    let mut cost = vec![vec![0i32; n]; n];
    for i in 0..n {
        cost[i][i] = freq[i];
    }

    for len in 2..=n {
        for i in 0..=(n - len) {
            let j = i + len - 1;
            cost[i][j] = i32::MAX;
            let freq_sum: i32 = freq[i..=j].iter().sum();

            for r in i..=j {
                let left = if r > i { cost[i][r - 1] } else { 0 };
                let right = if r < j { cost[r + 1][j] } else { 0 };
                let c = left + right + freq_sum;
                if c < cost[i][j] {
                    cost[i][j] = c;
                }
            }
        }
    }

    cost[0][n - 1]
}

object OptimalBST {

  def optimalBst(arr: Array[Int]): Int = {
    val n = arr(0)
    val freq = Array.tabulate(n)(i => arr(i + 1))

    val cost = Array.ofDim[Int](n, n)
    for (i <- 0 until n) cost(i)(i) = freq(i)

    for (len <- 2 to n) {
      for (i <- 0 to n - len) {
        val j = i + len - 1
        cost(i)(j) = Int.MaxValue
        val freqSum = (i to j).map(freq(_)).sum

        for (r <- i to j) {
          val left = if (r > i) cost(i)(r - 1) else 0
          val right = if (r < j) cost(r + 1)(j) else 0
          val c = left + right + freqSum
          if (c < cost(i)(j)) cost(i)(j) = c
        }
      }
    }

    cost(0)(n - 1)
  }
}

func optimalBst(_ arr: [Int]) -> Int {
    let n = arr[0]
    if n == 0 { return 0 }
    let freq = Array(arr[1...n])

    var cost = Array(repeating: Array(repeating: 0, count: n), count: n)
    for i in 0..<n { cost[i][i] = freq[i] }

    if n >= 2 {
        for len in 2...n {
            for i in 0...(n - len) {
                let j = i + len - 1
                cost[i][j] = Int.max
                var freqSum = 0
                for k in i...j { freqSum += freq[k] }

                for r in i...j {
                    let left = r > i ? cost[i][r - 1] : 0
                    let right = r < j ? cost[r + 1][j] : 0
                    let c = left + right + freqSum
                    if c < cost[i][j] { cost[i][j] = c }
                }
            }
        }
    }

    return cost[0][n - 1]
}

export function optimalBst(arr: number[]): number {
    const n = arr[0];
    const freq = arr.slice(1, n + 1);

    const cost: number[][] = Array.from({ length: n }, () => new Array(n).fill(0));
    for (let i = 0; i < n; i++) cost[i][i] = freq[i];

    for (let len = 2; len <= n; len++) {
        for (let i = 0; i <= n - len; i++) {
            const j = i + len - 1;
            cost[i][j] = Infinity;
            let freqSum = 0;
            for (let k = i; k <= j; k++) freqSum += freq[k];

